  AcDataDictionary.keyViews : {
    Views.actVwAccounteeAddressValues : {
      AcDDView.keyViewName : Views.actVwAccounteeAddressValues,
      AcDDView.keyViewQuery : "SELECT accountee_id,GROUP_CONCAT( DISTINCT TRIM(COALESCE(address_line_1, '') ||  CASE WHEN TRIM(COALESCE(address_line_2, '')) <> '' THEN ', ' ||  TRIM(address_line_2) ELSE '' END ||  CASE WHEN TRIM(COALESCE(postal_code, '')) <> '' THEN ', ' ||  TRIM(postal_code) ELSE '' END ||  CASE WHEN TRIM(COALESCE(city_name, '')) <> '' THEN ', '  || TRIM(city_name) ELSE '' END ||  CASE WHEN TRIM(COALESCE(state_name, '')) <> '' THEN ', ' ||  TRIM(state_name) ELSE '' END ||  CASE WHEN TRIM(COALESCE(country_name, '')) <> '' THEN ', ' ||  TRIM(country_name) ELSE '' END )) AS accountee_addresses FROM act_accountee_addresses  LEFT JOIN act_addresses ON act_addresses.address_id = act_accountee_addresses.address_id WHERE address_line_1 IS NOT NULL AND TRIM(address_line_1) <> '' GROUP BY accountee_id",
      AcDDView.keyViewColumns : {
        ActVwAccounteeAddressValues.accounteeId : {
          AcDDViewColumn.keyColumnName : ActVwAccounteeAddressValues.accounteeId,
          AcDDViewColumn.keyColumnSource : "table",
