    Views.actVwPartyAddressValues : {
      AcDDView.keyViewName : Views.actVwPartyAddressValues,
      AcDDView.keyViewQuery : "SELECT party_id,GROUP_CONCAT( DISTINCT TRIM(COALESCE(address_line_1, '') ||  CASE WHEN TRIM(COALESCE(address_line_2, '')) <> '' THEN ', ' ||  TRIM(address_line_2) ELSE '' END ||  CASE WHEN TRIM(COALESCE(postal_code, '')) <> '' THEN ', ' ||  TRIM(postal_code) ELSE '' END ||  CASE WHEN TRIM(COALESCE(city_name, '')) <> '' THEN ', '  || TRIM(city_name) ELSE '' END ||  CASE WHEN TRIM(COALESCE(state_name, '')) <> '' THEN ', ' ||  TRIM(state_name) ELSE '' END ||  CASE WHEN TRIM(COALESCE(country_name, '')) <> '' THEN ', ' ||  TRIM(country_name) ELSE '' END )) AS party_addresses FROM act_party_addresses  LEFT JOIN act_addresses ON act_addresses.address_id = act_party_addresses.address_id WHERE address_line_1 IS NOT NULL AND TRIM(address_line_1) <> '' GROUP BY party_id",
