    Views.actVwProductCategories : {
      AcDDView.keyViewName : Views.actVwProductCategories,
      AcDDView.keyViewQuery : "SELECT  purchase_taxing_schemes.taxing_scheme_name AS purchase_taxing_scheme_name, sale_taxing_schemes.taxing_scheme_name AS sale_taxing_scheme_name, purchase_tax_rates.tax_rate_name AS purchase_tax_rate_name, purchase_tax_rates.tax_rate_percentage AS purchase_tax_rate_percentage, sale_tax_rates.tax_rate_name AS sale_tax_rate_name, sale_tax_rates.tax_rate_percentage AS sale_tax_rate_percentage, json_object('media_path', media_path,'media_details', media_details) AS product_category_image_media, act_product_categories.* FROM act_product_categories  LEFT JOIN act_taxing_schemes as purchase_taxing_schemes ON act_product_categories.purchase_taxing_scheme_id = purchase_taxing_schemes.taxing_scheme_id LEFT JOIN act_taxing_schemes as sale_taxing_schemes ON act_product_categories.sale_taxing_scheme_id = sale_taxing_schemes.taxing_scheme_id LEFT JOIN act_tax_rates as purchase_tax_rates ON act_product_categories.purchase_tax_rate_id = purchase_tax_rates.tax_rate_id LEFT JOIN act_tax_rates as sale_tax_rates ON act_product_categories.sale_tax_rate_id = sale_tax_rates.tax_rate_id  LEFT JOIN act_medias ON act_product_categories.product_category_image_media_id = act_medias.media_id",
