    Views.actVwPurchaseInvoiceSummary : {
      AcDDView.keyViewName : Views.actVwPurchaseInvoiceSummary,
      AcDDView.keyViewQuery : "SELECT     pi.purchase_invoice_id,      IFNULL(p.products_count, 0) AS products_count,      ROUND(IFNULL(p.total_amount, 0)) AS total_amount,      ROUND(IFNULL(pay.total_paid_amount, 0), 4) AS total_paid_amount  FROM act_purchase_invoices pi  LEFT JOIN (     SELECT         purchase_invoice_id,         COUNT(purchase_invoice_product_id) AS products_count,         SUM(product_amount) AS total_amount     FROM act_purchase_invoice_products     GROUP BY purchase_invoice_id ) p ON p.purchase_invoice_id = pi.purchase_invoice_id  LEFT JOIN (     SELECT         purchase_invoice_id,         SUM(purchase_invoice_payment_amount) AS total_paid_amount     FROM act_purchase_invoice_payments     WHERE purchase_invoice_payment_status = 'PAID'     GROUP BY purchase_invoice_id ) pay ON pay.purchase_invoice_id = pi.purchase_invoice_id;",
      AcDDView.keyViewColumns : {
