    Views.actVwPurchaseOrderProducts : {
      AcDDView.keyViewName : Views.actVwPurchaseOrderProducts,
      AcDDView.keyViewQuery : "SELECT     (         COALESCE(pop.product_quantity, 0) *         COALESCE(pop.product_price_gross, 0)     ) AS gross_amount,      (         (             COALESCE(pop.product_quantity, 0) *             COALESCE(pop.product_price_gross, 0)         ) * (COALESCE(pop.discount_trade_percentage, 0) / 100)     ) AS discount_trade_amount,      (         (             (                 COALESCE(pop.product_quantity, 0) *                 COALESCE(pop.product_price_gross, 0)             ) * (1 - (COALESCE(pop.discount_trade_percentage, 0) / 100))         ) * (COALESCE(pop.discount_cash_percentage, 0) / 100)     ) AS discount_cash_amount,      (         (             (                 (                     COALESCE(pop.product_quantity, 0) *                     COALESCE(pop.product_price_gross, 0)                 ) * (1 - (COALESCE(pop.discount_trade_percentage, 0) / 100))             ) * (1 - (COALESCE(pop.discount_cash_percentage, 0) / 100))         ) * (COALESCE(pop.discount_rebate_percentage, 0) / 100)     ) AS discount_rebate_amount,      (         (             (                 (                     COALESCE(pop.product_quantity, 0) *                     COALESCE(pop.product_price_gross, 0)                 ) * (1 - (COALESCE(pop.discount_trade_percentage, 0) / 100))             ) * (1 - (COALESCE(pop.discount_cash_percentage, 0) / 100))         ) * (1 - (COALESCE(pop.discount_rebate_percentage, 0) / 100))     ) AS taxable_amount,      (         (             (                 (                     COALESCE(pop.product_quantity, 0) *                     COALESCE(pop.product_price_gross, 0)                 ) * (1 - (COALESCE(pop.discount_trade_percentage, 0) / 100))             ) * (1 - (COALESCE(pop.discount_cash_percentage, 0) / 100))         ) * (1 - (COALESCE(pop.discount_rebate_percentage, 0) / 100))         * (COALESCE(pop.tax_rate_percentage, 0) / 100)     ) AS tax_amount,      act_vw_products.product_name,     act_vw_products.product_image_media,     act_vw_products.hsn_code,     act_taxing_schemes.taxing_scheme_name,     act_tax_rates.tax_rate_name,     act_product_uoms.product_uom_name,     pop.*  FROM act_purchase_order_products pop LEFT JOIN act_vw_products     ON pop.product_id = act_vw_products.product_id LEFT JOIN act_product_uoms     ON pop.product_uom_id = act_product_uoms.product_uom_id LEFT JOIN act_taxing_schemes     ON pop.taxing_scheme_id = act_taxing_schemes.taxing_scheme_id LEFT JOIN act_tax_rates     ON pop.tax_rate_id = act_tax_rates.tax_rate_id;",
      AcDDView.keyViewColumns : {
        ActVwPurchaseOrderProducts.productName : {
