      AcDDView.keyViewQuery : "SELECT  (COALESCE(act_sale_invoice_chargeable_services.chargeable_service_quantity, 0) * COALESCE(act_sale_invoice_chargeable_services.chargeable_service_charge_gross, 0)) AS gross_amount, ((COALESCE(act_sale_invoice_chargeable_services.chargeable_service_quantity, 0) * COALESCE(act_sale_invoice_chargeable_services.chargeable_service_charge_gross, 0)) * (COALESCE(act_sale_invoice_chargeable_services.discount_trade_percentage, 0) / 100)) AS discount_trade_amount, (((COALESCE(act_sale_invoice_chargeable_services.chargeable_service_quantity, 0) * COALESCE(act_sale_invoice_chargeable_services.chargeable_service_charge_gross, 0)) * (1 - (COALESCE(act_sale_invoice_chargeable_services.discount_trade_percentage, 0) / 100))) * (COALESCE(act_sale_invoice_chargeable_services.discount_cash_percentage, 0) / 100)) AS discount_cash_amount, ((((COALESCE(act_sale_invoice_chargeable_services.chargeable_service_quantity, 0) * COALESCE(act_sale_invoice_chargeable_services.chargeable_service_charge_gross, 0)) * (1 - (COALESCE(act_sale_invoice_chargeable_services.discount_trade_percentage, 0) / 100))) * (1 - (COALESCE(act_sale_invoice_chargeable_services.discount_cash_percentage, 0) / 100))) * (COALESCE(act_sale_invoice_chargeable_services.discount_rebate_percentage, 0) / 100)) AS discount_rebate_amount, ((((COALESCE(act_sale_invoice_chargeable_services.chargeable_service_quantity, 0) * COALESCE(act_sale_invoice_chargeable_services.chargeable_service_charge_gross, 0)) * (1 - (COALESCE(act_sale_invoice_chargeable_services.discount_trade_percentage, 0) / 100))) * (1 - (COALESCE(act_sale_invoice_chargeable_services.discount_cash_percentage, 0) / 100))) * (1 - (COALESCE(act_sale_invoice_chargeable_services.discount_rebate_percentage, 0) / 100))) AS taxable_amount, (((((COALESCE(act_sale_invoice_chargeable_services.chargeable_service_quantity, 0) * COALESCE(act_sale_invoice_chargeable_services.chargeable_service_charge_gross, 0)) * (1 - (COALESCE(act_sale_invoice_chargeable_services.discount_trade_percentage, 0) / 100))) * (1 - (COALESCE(act_sale_invoice_chargeable_services.discount_cash_percentage, 0) / 100))) * (1 - (COALESCE(act_sale_invoice_chargeable_services.discount_rebate_percentage, 0) / 100))) * (COALESCE(act_sale_invoice_chargeable_services.tax_rate_percentage, 0) / 100)) AS tax_amount,act_chargeable_services.chargeable_service_name,  act_taxing_schemes.taxing_scheme_name, act_tax_rates.tax_rate_name, act_chargeable_service_uoms.chargeable_service_uom_name, act_sale_invoice_chargeable_services.* FROM act_sale_invoice_chargeable_services  LEFT JOIN act_chargeable_services ON act_sale_invoice_chargeable_services.chargeable_service_id= act_chargeable_services.chargeable_service_id LEFT JOIN act_chargeable_service_uoms ON act_sale_invoice_chargeable_services.chargeable_service_uom_id = act_chargeable_service_uoms.chargeable_service_uom_id  LEFT JOIN act_taxing_schemes ON act_sale_invoice_chargeable_services.taxing_scheme_id= act_taxing_schemes.taxing_scheme_id LEFT JOIN act_tax_rates ON act_sale_invoice_chargeable_services.tax_rate_id = act_tax_rates.tax_rate_id",
