    Views.actVwSaleInvoiceProducts : {
      AcDDView.keyViewName : Views.actVwSaleInvoiceProducts,
      AcDDView.keyViewQuery : "SELECT     (         COALESCE(sip.product_quantity, 0) *         COALESCE(sip.product_price_gross, 0)     ) AS gross_amount,      (         (             COALESCE(sip.product_quantity, 0) *             COALESCE(sip.product_price_gross, 0)         ) * (COALESCE(sip.discount_trade_percentage, 0) / 100)     ) AS discount_trade_amount,      (         (             (                 COALESCE(sip.product_quantity, 0) *                 COALESCE(sip.product_price_gross, 0)             ) * (1 - (COALESCE(sip.discount_trade_percentage, 0) / 100))         ) * (COALESCE(sip.discount_cash_percentage, 0) / 100)     ) AS discount_cash_amount,      (         (             (                 (                     COALESCE(sip.product_quantity, 0) *                     COALESCE(sip.product_price_gross, 0)                 ) * (1 - (COALESCE(sip.discount_trade_percentage, 0) / 100))             ) * (1 - (COALESCE(sip.discount_cash_percentage, 0) / 100))         ) * (COALESCE(sip.discount_rebate_percentage, 0) / 100)     ) AS discount_rebate_amount,      (         (             (                 (                     COALESCE(sip.product_quantity, 0) *                     COALESCE(sip.product_price_gross, 0)                 ) * (1 - (COALESCE(sip.discount_trade_percentage, 0) / 100))             ) * (1 - (COALESCE(sip.discount_cash_percentage, 0) / 100))         ) * (1 - (COALESCE(sip.discount_rebate_percentage, 0) / 100))     ) AS taxable_amount,      (         (             (                 (                     COALESCE(sip.product_quantity, 0) *                     COALESCE(sip.product_price_gross, 0)                 ) * (1 - (COALESCE(sip.discount_trade_percentage, 0) / 100))             ) * (1 - (COALESCE(sip.discount_cash_percentage, 0) / 100))         ) * (1 - (COALESCE(sip.discount_rebate_percentage, 0) / 100))         * (COALESCE(sip.tax_rate_percentage, 0) / 100)     ) AS tax_amount,      act_vw_products.product_name,     act_vw_products.hsn_code,     act_vw_products.product_image_media,     act_taxing_schemes.taxing_scheme_name,     act_tax_rates.tax_rate_name,     act_product_uoms.product_uom_name,     sip.*  FROM act_sale_invoice_products sip LEFT JOIN act_vw_products     ON sip.product_id = act_vw_products.product_id LEFT JOIN act_product_uoms     ON sip.product_uom_id = act_product_uoms.product_uom_id LEFT JOIN act_taxing_schemes     ON sip.taxing_scheme_id = act_taxing_schemes.taxing_scheme_id LEFT JOIN act_tax_rates     ON sip.tax_rate_id = act_tax_rates.tax_rate_id;",
      AcDDView.keyViewColumns : {
