    Views.actVwSaleInvoiceSummary : {
      AcDDView.keyViewName : Views.actVwSaleInvoiceSummary,
      AcDDView.keyViewQuery : "SELECT     si.sale_invoice_id,      IFNULL(p.products_count, 0) AS products_count,      ROUND(IFNULL(p.total_amount, 0)) AS total_amount,      ROUND(IFNULL(r.total_received_amount, 0), 4) AS total_received_amount  FROM act_sale_invoices si  LEFT JOIN (     SELECT         sale_invoice_id,         COUNT(sale_invoice_product_id) AS products_count,         SUM(product_amount) AS total_amount     FROM act_sale_invoice_products     GROUP BY sale_invoice_id ) p ON p.sale_invoice_id = si.sale_invoice_id  LEFT JOIN (     SELECT         sale_invoice_id,         SUM(sale_invoice_payment_amount) AS total_received_amount     FROM act_sale_invoice_payments     WHERE sale_invoice_payment_status = 'RECEIVED'     GROUP BY sale_invoice_id ) r ON r.sale_invoice_id = si.sale_invoice_id;",
      AcDDView.keyViewColumns : {
        ActVwSaleInvoiceSummary.saleInvoiceId : {
