    Views.actVwSaleQuotationChargeableServices : {
      AcDDView.keyViewName : Views.actVwSaleQuotationChargeableServices,
      AcDDView.keyViewQuery : "SELECT     (         COALESCE(sqcs.chargeable_service_quantity, 0) *         COALESCE(sqcs.chargeable_service_charge_gross, 0)     ) AS gross_amount,      (         (             COALESCE(sqcs.chargeable_service_quantity, 0) *             COALESCE(sqcs.chargeable_service_charge_gross, 0)         ) * (COALESCE(sqcs.discount_trade_percentage, 0) / 100)     ) AS discount_trade_amount,      (         (             (                 COALESCE(sqcs.chargeable_service_quantity, 0) *                 COALESCE(sqcs.chargeable_service_charge_gross, 0)             ) * (1 - (COALESCE(sqcs.discount_trade_percentage, 0) / 100))         ) * (COALESCE(sqcs.discount_cash_percentage, 0) / 100)     ) AS discount_cash_amount,      (         (             (                 (                     COALESCE(sqcs.chargeable_service_quantity, 0) *                     COALESCE(sqcs.chargeable_service_charge_gross, 0)                 ) * (1 - (COALESCE(sqcs.discount_trade_percentage, 0) / 100))             ) * (1 - (COALESCE(sqcs.discount_cash_percentage, 0) / 100))         ) * (COALESCE(sqcs.discount_rebate_percentage, 0) / 100)     ) AS discount_rebate_amount,      (         (             (                 (                     COALESCE(sqcs.chargeable_service_quantity, 0) *                     COALESCE(sqcs.chargeable_service_charge_gross, 0)                 ) * (1 - (COALESCE(sqcs.discount_trade_percentage, 0) / 100))             ) * (1 - (COALESCE(sqcs.discount_cash_percentage, 0) / 100))         ) * (1 - (COALESCE(sqcs.discount_rebate_percentage, 0) / 100))     ) AS taxable_amount,      (         (             (                 (                     COALESCE(sqcs.chargeable_service_quantity, 0) *                     COALESCE(sqcs.chargeable_service_charge_gross, 0)                 ) * (1 - (COALESCE(sqcs.discount_trade_percentage, 0) / 100))             ) * (1 - (COALESCE(sqcs.discount_cash_percentage, 0) / 100))         ) * (1 - (COALESCE(sqcs.discount_rebate_percentage, 0) / 100))         * (COALESCE(sqcs.tax_rate_percentage, 0) / 100)     ) AS tax_amount,      act_chargeable_services.chargeable_service_name,     act_taxing_schemes.taxing_scheme_name,     act_tax_rates.tax_rate_name,     act_chargeable_service_uoms.chargeable_service_uom_name,     sqcs.*  FROM act_sale_quotation_chargeable_services sqcs LEFT JOIN act_chargeable_services     ON sqcs.chargeable_service_id = act_chargeable_services.chargeable_service_id LEFT JOIN act_chargeable_service_uoms     ON sqcs.chargeable_service_uom_id = act_chargeable_service_uoms.chargeable_service_uom_id LEFT JOIN act_taxing_schemes     ON sqcs.taxing_scheme_id = act_taxing_schemes.taxing_scheme_id LEFT JOIN act_tax_rates     ON sqcs.tax_rate_id = act_tax_rates.tax_rate_id;",
      AcDDView.keyViewColumns : {
        ActVwSaleQuotationChargeableServices.chargeableServiceName : {
          AcDDViewColumn.keyColumnName : ActVwSaleQuotationChargeableServices.chargeableServiceName,
          AcDDViewColumn.keyColumnSource : "table",
          AcDDViewColumn.keyColumnSourceName : "act_chargeable_services",
          AcDDViewColumn.keyColumnSourceOriginalColumn : "chargeable_service_name",
          AcDDViewColumn.keyColumnType : AcEnumDDColumnType.string,
          AcDDViewColumn.keyColumnProperties : {
          }
        },
        ActVwSaleQuotationChargeableServices.taxingSchemeName : {
          AcDDViewColumn.keyColumnName : ActVwSaleQuotationChargeableServices.taxingSchemeName,
          AcDDViewColumn.keyColumnSource : "table",
          AcDDViewColumn.keyColumnSourceName : "act_taxing_schemes",
          AcDDViewColumn.keyColumnSourceOriginalColumn : "taxing_scheme_name",
          AcDDViewColumn.keyColumnType : AcEnumDDColumnType.string,
          AcDDViewColumn.keyColumnProperties : {
          }
        },
        ActVwSaleQuotationChargeableServices.taxRateName : {
          AcDDViewColumn.keyColumnName : ActVwSaleQuotationChargeableServices.taxRateName,
          AcDDViewColumn.keyColumnSource : "table",
