    Views.actVwSaleQuotationProducts : {
      AcDDView.keyViewName : Views.actVwSaleQuotationProducts,
      AcDDView.keyViewQuery : "SELECT     (         COALESCE(sqp.product_quantity, 0) *         COALESCE(sqp.product_price_gross, 0)     ) AS gross_amount,      (         (             COALESCE(sqp.product_quantity, 0) *             COALESCE(sqp.product_price_gross, 0)         ) * (COALESCE(sqp.discount_trade_percentage, 0) / 100)     ) AS discount_trade_amount,      (         (             (                 COALESCE(sqp.product_quantity, 0) *                 COALESCE(sqp.product_price_gross, 0)             ) * (1 - (COALESCE(sqp.discount_trade_percentage, 0) / 100))         ) * (COALESCE(sqp.discount_cash_percentage, 0) / 100)     ) AS discount_cash_amount,      (         (             (                 (                     COALESCE(sqp.product_quantity, 0) *                     COALESCE(sqp.product_price_gross, 0)                 ) * (1 - (COALESCE(sqp.discount_trade_percentage, 0) / 100))             ) * (1 - (COALESCE(sqp.discount_cash_percentage, 0) / 100))         ) * (COALESCE(sqp.discount_rebate_percentage, 0) / 100)     ) AS discount_rebate_amount,      (         (             (                 (                     COALESCE(sqp.product_quantity, 0) *                     COALESCE(sqp.product_price_gross, 0)                 ) * (1 - (COALESCE(sqp.discount_trade_percentage, 0) / 100))             ) * (1 - (COALESCE(sqp.discount_cash_percentage, 0) / 100))         ) * (1 - (COALESCE(sqp.discount_rebate_percentage, 0) / 100))     ) AS taxable_amount,      (         (             (                 (                     COALESCE(sqp.product_quantity, 0) *                     COALESCE(sqp.product_price_gross, 0)                 ) * (1 - (COALESCE(sqp.discount_trade_percentage, 0) / 100))             ) * (1 - (COALESCE(sqp.discount_cash_percentage, 0) / 100))         ) * (1 - (COALESCE(sqp.discount_rebate_percentage, 0) / 100))         * (COALESCE(sqp.tax_rate_percentage, 0) / 100)     ) AS tax_amount,      act_vw_products.product_name,     act_vw_products.hsn_code,     act_vw_products.product_image_media,     act_taxing_schemes.taxing_scheme_name,     act_tax_rates.tax_rate_name,     act_product_uoms.product_uom_name,     sqp.*  FROM act_sale_quotation_products sqp LEFT JOIN act_vw_products     ON sqp.product_id = act_vw_products.product_id LEFT JOIN act_product_uoms     ON sqp.product_uom_id = act_product_uoms.product_uom_id LEFT JOIN act_taxing_schemes     ON sqp.taxing_scheme_id = act_taxing_schemes.taxing_scheme_id LEFT JOIN act_tax_rates     ON sqp.tax_rate_id = act_tax_rates.tax_rate_id;",
      AcDDView.keyViewColumns : {
        ActVwSaleQuotationProducts.productName : {
          AcDDViewColumn.keyColumnName : ActVwSaleQuotationProducts.productName,
          AcDDViewColumn.keyColumnSource : "view",
          AcDDViewColumn.keyColumnSourceName : "act_vw_products",
          AcDDViewColumn.keyColumnSourceOriginalColumn : "product_name",
          AcDDViewColumn.keyColumnType : AcEnumDDColumnType.text,
          AcDDViewColumn.keyColumnProperties : {
          }
        },
        ActVwSaleQuotationProducts.hsnCode : {
          AcDDViewColumn.keyColumnName : ActVwSaleQuotationProducts.hsnCode,
          AcDDViewColumn.keyColumnSource : "view",
          AcDDViewColumn.keyColumnSourceName : "act_vw_products",
          AcDDViewColumn.keyColumnSourceOriginalColumn : "hsn_code",
          AcDDViewColumn.keyColumnType : AcEnumDDColumnType.string,
          AcDDViewColumn.keyColumnProperties : {
          }
        },
        ActVwSaleQuotationProducts.taxingSchemeName : {
