    Views.actVwStockAtStorageLocation : {
      AcDDView.keyViewName : Views.actVwStockAtStorageLocation,
      AcDDView.keyViewQuery : "SELECT  SUM(in_total_quantity ) AS in_total_quantity ,  SUM(out_total_quantity) AS out_total_quantity,  SUM(IIF(in_total_quantity IS NULL,0,in_total_quantity ) - IIF(out_total_quantity IS NULL,0,out_total_quantity)) AS total_closing_stock,  (SUM(IIF(in_total_quantity IS NULL,0,in_total_quantity ) - IIF(out_total_quantity IS NULL,0,out_total_quantity)) / IIF(act_vw_current_product_stock_details.stock_uom_quantity IS NULL,1,act_vw_current_product_stock_details.stock_uom_quantity)) AS closing_stock, act_vw_current_product_stock_details.stock_uom_id, act_vw_current_product_stock_details.stock_uom_name, act_vw_current_product_stock_details.stock_uom_quantity, act_vw_products.*,act_vw_inventory_tracking_entries.storage_location_id FROM act_vw_products  LEFT JOIN act_vw_inventory_tracking_entries ON act_vw_products.product_id = act_vw_inventory_tracking_entries.product_id  LEFT JOIN act_vw_current_product_stock_details ON act_vw_current_product_stock_details.product_id = act_vw_products.product_id  GROUP BY act_vw_products.product_id,storage_location_id",
