    Views.actVwTransactionSummary : {
      AcDDView.keyViewName : Views.actVwTransactionSummary,
      AcDDView.keyViewQuery : "SELECT act_transactions.transaction_id, total_debit_amount, total_credit_amount, total_debit_entries_count, total_credit_entries_count, reflecting_debit_ledger_accounts, reflecting_credit_ledger_accounts FROM act_transactions LEFT JOIN (SELECT SUM(transaction_entry_amount) AS total_debit_amount,COUNT(transaction_entry_id) AS total_debit_entries_count,GROUP_CONCAT(ledger_account_name,', ') AS reflecting_debit_ledger_accounts, transaction_id FROM act_vw_transaction_entries WHERE is_credit=0 GROUP BY transaction_id) AS debit_summary ON act_transactions.transaction_id = debit_summary.transaction_id LEFT JOIN  (SELECT SUM(transaction_entry_amount) AS total_credit_amount,COUNT(transaction_entry_id) AS total_credit_entries_count,GROUP_CONCAT(ledger_account_name,', ') AS reflecting_credit_ledger_accounts, transaction_id FROM act_vw_transaction_entries WHERE is_credit=1 GROUP BY transaction_id) AS credit_summary ON act_transactions.transaction_id = credit_summary.transaction_id",
